class Solution:
    def maxArrayValue(self, nums: List[int]) -> int:
        n = len(nums)
        # Start from the end of the array and move backwards
        for i in range(n - 2, -1, -1):
            # If current element is less than or equal to the next one, combine them
            if nums[i] <= nums[i + 1]:
                nums[i] += nums[i + 1]
        # The maximum value in the final array is the maximum of the modified nums
        return max(nums)
